def ensure_dir(path):
    """逐级创建目录，已存在则忽略 / mkdir -p equivalent."""
    cur = ""
    for part in path.strip("/").split("/"):
        cur += "/" + part
        try:
            os.mkdir(cur)
        except Exception:
            pass


